function setFaviconForTheme(e){const t=e==="dark",n=document.getElementById("favicon-32"),s=document.getElementById("favicon-16");if(!n||!s)return;n.href=t?"/images/favicons/favicon-dark-32.png":"/images/favicons/favicon-light-32.png",s.href=t?"/images/favicons/favicon-dark-16.png":"/images/favicons/favicon-light-16.png"}function getActiveTheme(){const e=document.body;return e.classList.contains("colorscheme-dark")?"dark":e.classList.contains("colorscheme-light")?"light":window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light"}document.addEventListener("DOMContentLoaded",function(){setFaviconForTheme(getActiveTheme())}),document.addEventListener("themeChanged",function(){setFaviconForTheme(getActiveTheme())})